Код
Вот код схемы с комментариями:
// Пины SPI для ESP32-C3 Super Mini (GPIO)
#define SCK 4 // Serial Clock - тактовый сигнал шины SPI
#define MISO 5 // Master In Slave Out - линия данных от карты к контроллеру
#define MOSI 6 // Master Out Slave In - линия данных от контроллера к карте
#define CS 7 // Chip Select - выбор ведомого устройства (SD-карты)

// Период опроса датчиков и записи в мс (1 секунда)
#define PRD_WRITE 1000

#include <WiFi.h>
#include <WebServer.h>

const char *ssid = "ESPstation"; // Имя создаваемой точки доступа Wi-Fi

WebServer server(80); // Создание веб-сервера на стандартном порту HTTP (80)

#include "SPI.h" // Библиотека аппаратного SPI
#include "SD.h" // Библиотека для работы с SD-картами через FS API
#include "FS.h" // Абстракция файловой системы Arduino

#include <GyverBME280.h> // Оптимизированная библиотека для датчика BME280 (температура, давление, влажность)
GyverBME280 bme;

#include <Adafruit_AHTX0.h> // Официальная библиотека Adafruit для AHT10/AHT20 (температура, влажность)
Adafruit_AHTX0 aht;

float dataBus[] = {0.0, 0.0, 0.0}; 
/* Массив для хранения усредненных показаний:
dataBus[0] — Температура (°C)
dataBus[1] — Давление (мм рт. ст.)
dataBus[2] — Влажность (%)
*/

/* Вспомогательная функция: перевод давления из Паскалей (возвращает BME280) 
в миллиметры ртутного столба по формуле: 1 мм рт. ст. ≈ 133.322 Па */
float pressureToMmHg(float pa) {
 return pa / 133.322f;
}

void get_data() {
 sensors_event_t humidity, temp; // Структуры для получения сырых данных от I2C-датчика
 aht.getEvent(&humidity, &temp);

 /* Сборка финальных значений в массиве dataBus.
 Важно: температура берется как среднее арифметическое между двумя датчиками,
 чтобы сгладить погрешности измерений. */
 dataBus[0] = (temp.temperature + bme.readTemperature()) / 2.0;
 dataBus[1] = pressureToMmHg(bme.readPressure());
 dataBus[2] = humidity.relative_humidity;

 // Открытие файла на SD-карте в режиме дозаписи (если файла нет — он создастся)
 File file = SD.open("/ESPstation_logs.txt", FILE_APPEND);

 if (file) {
 /* Запись данных БЕЗ использования класса String (экономия оперативной памяти!).
 Метод print() автоматически преобразует числа в текстовое представление.
 Использование F("...") поместит строковые литералы во флеш-память вместо RAM. */
 file.print(F("time after launch:"));
 file.print(millis() / 60000); // Время работы в минутах
 file.print(F(", temp: "));
 file.print(dataBus[0], 1); // 1 знак после запятой
 file.print(F(", MmHg: "));
 file.print(dataBus[1], 1);
 file.print(F(", humd: "));
 file.print(dataBus[2], 1);
 file.println(); // Добавляем перенос строки (\n)

 file.close(); // Обязательно закрываем файл, иначе данные могут остаться в буфере и не записаться физически
 } else {
 Serial.println(F("Failed to open file for writing"));
 }
}

void handleRoot() {
 // Формирование HTML-страницы "на лету"
 String html = "<!DOCTYPE html>";
 html += "<html><head>";
 // Автоматическая перезагрузка страницы каждые 3 секунды для обновления данных без JS
 html += "<meta http-equiv='refresh' content='3'>";
 html += "<meta charset='UTF-8'>";

 // Инлайн-стили для оформления интерфейса метеостанции
 html += "<style>";
 html += "body { font-family: Montserrat, sans-serif; max-width: 600px; margin: 40px auto; padding: 20px; background: #f0f4f8; }";
 html += "h1 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }";
 html += "h2 { color: #34495e; margin-top: 30px; }";
 html += ".data-box { background: white; padding: 20px; border-radius: 10px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); margin: 15px 0; }";
 html += "</style>";
 html += "</head><body>";
 html += "<h1>ESPstation: локальная метеостанция</h1>";

 // Блок вывода комнатной температуры и влажности
 html += "<div class='data-box'>";
 html += "<h2>Комната</h2>";
 html += "<p>Температура: " + String(dataBus[0], 1) + " °C</p>";
 html += "<p>Влажность: " + String(dataBus[2], 1) + " %</p>";
 html += "</div>";

 // Блок вывода атмосферного давления
 html += "<div class='data-box'>";
 html += "<h2>Давление</h2>";
 html += "<p>Давление: " + String(dataBus[1], 1) + " мм рт. ст.</p>";
 html += "</div>";

 html += "</body></html>";
 server.send(200, "text/html", html); // Отправка сформированного кода браузеру
}

void setup() {
 Serial.begin(115200); // Скорость монитора порта
 delay(2000); // Задержка для корректного отображения сообщений при подаче питания
 Serial.println("\n=== Start ESPstation ===");

 // Инициализация SPI с явным указанием пинов (актуально для кастомных плат или переназначения GPIO)
 SPI.begin(SCK, MISO, MOSI, CS);

 // Небольшая задержка для стабилизации питания карты после подачи напряжения
 delay(500);

 // Инициализация SD карты. 
 // Указываем пин CS и максимальную частоту SPI (4 МГц для стабильности на макетке/длинных проводах)
 if (!SD.begin(CS, SPI, 4000000)) {
 Serial.println(F("Card Mount Failed! Check wiring and power."));
 return; // Выходим из setup, дальнейшая работа невозможна без накопителя
 }

 uint8_t cardType = SD.cardType();
 if (cardType == CARD_NONE) {
 Serial.println(F("No SD card attached"));
 return;
 }

 // Диагностика типа и объема установленной карты
 Serial.print(F("SD Card Type: "));
 if (cardType == CARD_MMC) Serial.println(F("MMC"));
 else if (cardType == CARD_SD) Serial.println(F("SDSC"));
 else if (cardType == CARD_SDHC) Serial.println(F("SDHC"));
 else Serial.println(F("UNKNOWN"));

 uint64_t cardSize = SD.cardSize() / (1024 * 1024);
 Serial.printf(F("SD Card Size: %lluMB\n"), cardSize);

 // Явная инициализация I2C ПЕРЕД использованием библиотек сенсоров
 Wire.begin();
 delay(100); // Даем время шине стабилизироваться

 // Инициализация BME280 по адресу 0x77 (адрес зависит от подтяжки пина SDO на плате)
 if (!bme.begin(0x77)) {
 Serial.println(F("BME280 not found!"));
 }

 // Инициализация AHT (автоматически ищет адрес на шине)
 if (!aht.begin()) {
 Serial.println(F("AHT not found!"));
 }

 // Поднятие собственной точки доступа (SoftAP). Станция подключается напрямую к модулю.
 WiFi.softAP(ssid);
 Serial.print(F("http://"));
 Serial.println(WiFi.softAPIP()); // Выводим IP-адрес точки доступа в монитор

 // Привязка корневого пути ("/") к функции генерации HTML
 server.on("/", handleRoot);
 server.begin(); // Запуск веб-сервера

 Serial.println(F("\nInitialization and test complete!"));
}

void loop() {
 static uint32_t tmr = 0; // Таймер периодических задач (статик сохраняет значение между итерациями)

 // Неблокирующий таймер: проверка раз в секунду (PRD_WRITE)
 if (millis() - tmr >= PRD_WRITE) {
 tmr = millis(); // Сброс опорной метки времени
 get_data(); // Чтение сенсоров и запись на SD
 }

 // Обработка входящих запросов от браузера (обязательно вызывать в цикле)
 server.handleClient();
}
Тесты
Итак, подключаем плату к питанию, ждем пару секунд и вот:
Веб-страница
Данные с карты
Всё исправно работает!
Итоги
Итак, я сделал оффлайн погодный логгер.
Идеи по улучшению:
Сделать приложение для чтения, вывода и прогнозирования данных
Добавить радиатор на плату esp
Сделать корпус
Пишите ваши идеи по доработке в комментариях, спасибо за внимание!

TL;DR
Посмотреть код целиком можно тут:
https://github.com/kubarskii/simple-di
Статья скорее рассчитана на начинающих разработчиков, но для ее понимания потребуется некоторое время и базовое представление об архитектуре приложений и паттернах. Перед чтением рекомендую познакомиться с принципами DDD и SOLID, особенно с буквой (D).
Я уже давно пытаюсь придумать, как можно сделать достойный DI-контейнер на ванильном JavaScript. Несколько раз я уже подходил к этой задаче, пробовал разные варианты, но отсутствие полноценной рефлексии и строгой типизации каждый раз сильно ограничивало возможные решения. Конечно, можно явно перечислять зависимости, хранить их в статических свойствах классов или использовать отдельный реестр метаданных, даже парсить исходный код классов, но обычно в какой-то момент такой контейнер либо становится слишком многословным, либо начинает напоминать плохо реализованный service locator.
В этот раз мне, кажется, удалось найти более интересный подход (возможно его находили и до меня). Он основан на том, что в JavaScript классы являются обычными значениями: их можно динамически создавать, передавать в функции, дополнять метаданными и использовать как токены. В результате получился небольшой DI-контейнер без TypeScript, декораторов и
reflect-metadata
.
Пока это эксперимент и попытка проверить саму идею, а не готовая библиотека. Тем не менее результат уже выглядит достойно, и после небольшой доработки я вполне мог бы попробовать использовать такой подход в реальном проекте. В статье разберем, как устроен контейнер, почему я решил отказаться от автоматического анализа конструкторов и как применить его в небольшом DDD-примере с корзиной товаров.
Когда речь заходит о dependency injection в JavaScript, разговор обычно быстро сводится к TypeScript, декораторам и
reflect-metadata
. Класс помечается как injectable, типы параметров конструктора превращаются в метаданные, а контейнер пытается самостоятельно понять, что именно нужно передать в каждый аргумент.
При этом сам JavaScript уже содержит почти все, что нужно для простого DI-контейнера. Класс в JavaScript является обычным runtime-значением. Его можно создать внутри функции, передать в другую функцию, использовать как ключ в
Map
, дополнить собственными свойствами и вернуть наружу. Значит, список зависимостей можно объявить прямо в момент создания класса, не пытаясь восстановить его позднее из типов, имен аргументов или результата
Function.prototype.toString()
.
Далее мы соберем небольшой DI-контейнер на чистом JavaScript, добавим
singleton
,
scoped
и
transient
lifetime, а затем применим его в более реалистичном примере с DDD-корзиной. Доменный слой останется независимым от контейнера, а DI будет отвечать только за сборку application и infrastructure слоев.
Почему обычный JavaScript не может вывести зависимости автоматически
Представим простой сервис:
class CartApplicationService {
 constructor(repository, catalog, discountPolicy) {
 this.repository = repository;
 this.catalog = catalog;
 this.discountPolicy = discountPolicy;
 }
}
Во время выполнения JavaScript видит функцию-конструктор, но не знает, что
repository
должен реализовывать порт репозитория корзин,
catalog
должен быть каталогом товаров, а
discountPolicy
должен рассчитывать скидку. Имена аргументов не являются контрактом. После минификации они легко превращаются в
a
,
b
и
c
, а значения по умолчанию, деструктуризация и rest-параметры делают разбор сигнатуры еще менее надежным.
Можно написать собственный аналог
reflect-metadata
на
WeakMap
, но он решит только задачу хранения. Кто-то все равно должен положить туда список зависимостей. Поэтому можно убрать промежуточное хранилище и объявить зависимости в функции, которая создает класс.
Желаемый API будет выглядеть примерно так:
const CartApplicationService = component(
 {
 name: "CartApplicationService",
 lifetime: "scoped",
 inject: {
 carts: CART_REPOSITORY,
 catalog: PRODUCT_CATALOG,
 discounts: DISCOUNT_POLICY,
 },
 },
 () => class {
 constructor({ carts, catalog, discounts }) {
 this.carts = carts;
 this.catalog = catalog;
 this.discounts = discounts;
 }
 },
);
В этом варианте класс создается динамически, получает стабильное runtime-имя и одновременно сохраняет описание своих зависимостей. Сам класс можно использовать как DI-токен, а для абстрактных портов удобно использовать
Symbol
.
Создаем компонент
Начнем с минимальной функции
component()
:
const COMPONENT_METADATA = Symbol("di.component.metadata");

const LIFETIMES = new Set([
 "singleton",
 "scoped",
 "transient",
]);

function component(
 {
 name,
 inject = {},
 lifetime = "transient",
 },
 classFactory,
) {
 if (!name) {
 throw new TypeError("Component name is required");
 }

 if (!LIFETIMES.has(lifetime)) {
 throw new TypeError(`Unsupported lifetime: ${lifetime}`);
 }

 const ComponentClass = classFactory();

 if (typeof ComponentClass !== "function") {
 throw new TypeError("classFactory must return a class");
 }

 Object.defineProperties(ComponentClass, {
 name: {
 value: name,
 configurable: true,
 },
 [COMPONENT_METADATA]: {
 value: Object.freeze({
 inject: Object.freeze({ ...inject }),
 lifetime,
 }),
 enumerable: false,
 configurable: false,
 writable: false,
 },
 });

 return ComponentClass;
}
Мы не добавляем ничего в глобальный
Reflect
и не заводим отдельный реестр метаданных. Описание хранится прямо на функции класса под закрытым
Symbol
. Снаружи его нельзя случайно получить по строковому имени, оно не появляется при обычном перечислении свойств, но контейнер может прочитать его в момент регистрации.
Имя класса задается явно. Для работы DI оно не требуется, потому что идентичность класса определяется самой функцией, но хорошее имя полезно в stack trace, сообщениях об ошибках и отладчике.
Для получения описания достаточно небольшой функции:
function getComponentMetadata(ComponentClass) {
 return ComponentClass[COMPONENT_METADATA] ?? null;
}
Токены: классы и Symbol
Если зависимость представлена конкретным классом, отдельный токен не нужен:
container.registerClass(Logger);
container.resolve(Logger);
Класс здесь одновременно является конструктором и ключом в
Map
. Это удобно для конкретных сервисов, которые не имеют нескольких реализаций.
Для портов лучше использовать
Symbol
:
const CART_REPOSITORY = Symbol("CartRepository");
const PRODUCT_CATALOG = Symbol("ProductCatalog");
const DISCOUNT_POLICY = Symbol("DiscountPolicy");
Application-слой зависит от таких токенов, а composition root связывает их с конкретными реализациями:
container.registerClass(InMemoryCartRepository, {
 token: CART_REPOSITORY,
});
Так доменная и прикладная логика не знают, используется ли память, PostgreSQL, Redis или внешний HTTP API.
Реализуем контейнер
Контейнер будет поддерживать три вида провайдеров:
Готовое значение.
Класс.
Фабрику.
Также добавим три времени жизни:
singleton
создает один экземпляр на корневой контейнер;
scoped
создает один экземпляр внутри request scope;
transient
создает новый экземпляр при каждом разрешении.
Основная часть контейнера выглядит так:
class Container {
 #providers = new Map();
 #singletons = new Map();

 registerValue(token, value) {
 this.#providers.set(token, {
 type: "value",
 value,
 lifetime: "singleton",
 inject: {},
 });

 return this;
 }

 registerClass(
 ComponentClass,
 {
 token = ComponentClass,
 inject,
 lifetime,
 } = {},
 ) {
 const metadata = getComponentMetadata(ComponentClass) ?? {
 inject: {},
 lifetime: "transient",
 };

 this.#providers.set(token, {
 type: "class",
 ComponentClass,
 inject: inject ?? metadata.inject,
 lifetime: lifetime ?? metadata.lifetime,
 });

 return this;
 }

 registerFactory(
 token,
 {
 inject = {},
 lifetime = "transient",
 factory,
 },
 ) {
 this.#providers.set(token, {
 type: "factory",
 inject,
 lifetime,
 factory,
 });

 return this;
 }
}
Самая важная часть находится в
resolve()
. Контейнер получает описание провайдера, рекурсивно разрешает зависимости, после чего создает экземпляр:
#resolve(token, scope, path) {
 if (scope?.hasOverride(token)) {
 return scope.getOverride(token);
 }

 const provider = this.#providers.get(token);

 if (!provider) {
 throw new Error(`Provider is not registered: ${String(token)}`);
 }

 if (
 provider.lifetime === "singleton" &&
 this.#singletons.has(token)
 ) {
 return this.#singletons.get(token);
 }

 if (provider.lifetime === "scoped") {
 if (!scope) {
 throw new Error("Scoped provider must be resolved from a scope");
 }

 if (scope.hasCached(token)) {
 return scope.getCached(token);
 }
 }

 if (path.includes(token)) {
 throw new Error("Circular dependency detected");
 }

 const nextPath = [...path, token];
 const dependencies = {};

 for (const [name, dependencyToken] of Object.entries(provider.inject)) {
 dependencies[name] = this.#resolve(
 dependencyToken,
 scope,
 nextPath,
 );
 }

 const instance = provider.type === "class"
 ? new provider.ComponentClass(dependencies)
 : provider.type === "factory"
 ? provider.factory(dependencies)
 : provider.value;

 if (provider.lifetime === "singleton") {
 this.#singletons.set(token, instance);
 }

 if (provider.lifetime === "scoped") {
 scope.setCached(token, instance);
 }

 return instance;
}
Здесь же проверяется циклическая зависимость. В полной версии из примера ошибка содержит всю цепочку токенов, например:
Circular dependency detected: CartService -> PricingService -> CartService
Почему зависимости передаются объектом
Контейнер мог бы хранить массив токенов и вызывать класс так:
new Service(repository, logger, clock);
Но объект с именованными зависимостями удобнее:
new Service({ repository, logger, clock });
Порядок полей перестает быть частью контракта. При добавлении новой зависимости не нужно синхронно менять позицию в массиве и позицию аргумента конструктора. Кроме того, описание компонента читается как небольшая схема:
inject: {
 carts: CART_REPOSITORY,
 catalog: PRODUCT_CATALOG,
 discounts: DISCOUNT_POLICY,
}
Контейнер при этом не выполняет property injection. Все зависимости по-прежнему приходят через конструктор, поэтому экземпляр нельзя получить в частично инициализированном состоянии.
Добавляем request scope
Для веб-приложения одного singleton и transient обычно недостаточно. Например, application service, unit of work или контекст текущего пользователя должны жить в пределах одного запроса.
Scope хранит собственный кеш и набор переопределений:
class Scope {
 #cache = new Map();

 constructor(container, overrides) {
 this.container = container;
 this.overrides = overrides;
 }

 resolve(token) {
 return this.container.resolveFromScope(token, this);
 }

 hasCached(token) {
 return this.#cache.has(token);
 }

 getCached(token) {
 return this.#cache.get(token);
 }

 setCached(token, value) {
 this.#cache.set(token, value);
 }
}
Контекст запроса не нужно регистрировать глобально. Его можно передать при создании scope:
const request = container.createScope([
 [REQUEST_CONTEXT, { id: "request-42" }],
]);

const service = request.resolve(CartApplicationService);
Любой scoped-компонент будет повторно использоваться внутри этого request scope, но другой запрос получит другой экземпляр.
Посмотрим на примере
Теперь перейдем к простому вполне прикладному примеру. В нем есть aggregate
Cart
, value object
Money
, application service, репозиторий, каталог товаров, скидочная политика и event bus.
Если на этом моменте воозникают вопросы, то рекомендую глянуть DDD. DDD делят обычно на тактический и стратегический, сейчас нас интересует тактический.
Важно, что
Cart
и
Money
ничего не знают о
component()
, контейнере и lifetime. DI не должен проникать в каждую сущность проекта. Доменная модель создается обычным JavaScript-кодом и защищает свои инварианты самостоятельно.
Упрощенный value object денег:
class Money {
 constructor(cents, currency = "EUR") {
 if (!Number.isSafeInteger(cents)) {
 throw new TypeError("Money must be stored as integer cents");
 }

 if (cents < 0) {
 throw new Error("Money cannot be negative");
 }

 this.cents = cents;
 this.currency = currency;
 Object.freeze(this);
 }

 add(other) {
 if (this.currency !== other.currency) {
 throw new Error("Currency mismatch");
 }

 return new Money(this.cents + other.cents, this.currency);
 }

 multiply(quantity) {
 return new Money(this.cents * quantity, this.currency);
 }
}
Aggregate корзины отвечает за добавление товаров, изменение количества, применение купона и checkout. Он не позволяет добавлять товар после оформления и не разрешает оформить пустую корзину:
class Cart {
 #items = new Map();
 #events = [];

 addProduct({ sku, name, unitPrice, quantity = 1 }) {
 this.#assertOpen();
 this.#assertQuantity(quantity);

 const current = this.#items.get(sku);
 const nextQuantity = (current?.quantity ?? 0) + quantity;

 this.#assertQuantity(nextQuantity);

 this.#items.set(sku, {
 sku,
 name,
 unitPrice,
 quantity: nextQuantity,
 });
 }

 checkout({ discountPolicy, now }) {
 this.#assertOpen();

 if (this.#items.size === 0) {
 throw new Error("Cannot checkout an empty cart");
 }

 const subtotal = this.subtotal();
 const discount = discountPolicy.calculate({ cart: this, subtotal });
 const total = subtotal.subtract(discount);

 this.status = "checked-out";

 this.#events.push({
 type: "CartCheckedOut",
 occurredAt: now.toISOString(),
 payload: {
 cartId: this.id,
 total: total.toJSON(),
 },
 });

 return { subtotal, discount, total };
 }
}
Скидочная политика передается в доменную операцию явно. Это доменный сервис, который может иметь несколько реализаций. Сам aggregate не обращается к контейнеру и не ищет сервис через service locator.
Application service как компонент
Application service координирует сценарий. Он загружает aggregate, получает товар из каталога, вызывает доменную операцию и сохраняет новое состояние:
const CartApplicationService = component(
 {
 name: "CartApplicationService",
 lifetime: "scoped",
 inject: {
 carts: CART_REPOSITORY,
 catalog: PRODUCT_CATALOG,
 discounts: DISCOUNT_POLICY,
 events: EVENT_BUS,
 createId: ID_GENERATOR,
 clock: CLOCK,
 request: REQUEST_CONTEXT,
 },
 },
 () => class {
 constructor({
 carts,
 catalog,
 discounts,
 events,
 createId,
 clock,
 request,
 }) {
 this.carts = carts;
 this.catalog = catalog;
 this.discounts = discounts;
 this.events = events;
 this.createId = createId;
 this.clock = clock;
 this.request = request;
 }

 async addProduct(cartId, sku, quantity = 1) {
 const cart = await this.carts.getById(cartId);
 const product = await this.catalog.getBySku(sku);

 cart.addProduct({
 ...product,
 quantity,
 });

 await this.carts.save(cart);
 return cart.toView(this.discounts);
 }

 async checkout(cartId) {
 const cart = await this.carts.getById(cartId);
 const totals = cart.checkout({
 discountPolicy: this.discounts,
 now: this.clock(),
 });

 await this.carts.save(cart);
 await this.events.publishAll(cart.pullDomainEvents());

 return totals;
 }
 },
);
Scoped lifetime здесь выбран не потому, что сам сервис хранит важное состояние, а потому, что позднее в этот же scope можно добавить unit of work, transaction context или identity map. В небольшом примере сервис можно сделать transient, но request scope показывает, как контейнер будет вести себя в настоящем приложении.
Infrastructure-реализации
Репозиторий можно зарегистрировать под абстрактным токеном:
const InMemoryCartRepository = component(
 {
 name: "InMemoryCartRepository",
 lifetime: "singleton",
 },
 () => class {
 #storage = new Map();

 async getById(id) {
 const snapshot = this.#storage.get(id);
 return snapshot ? new Cart(snapshot) : null;
 }

 async save(cart) {
 this.#storage.set(cart.id, cart.toSnapshot());
 }
 },
);
In-memory реализация хранит snapshots, а не ссылки на aggregate. Это небольшая, но полезная деталь. Если репозиторий просто вернет тот же объект из
Map
, изменение aggregate произойдет еще до вызова
save()
, и тестовый репозиторий будет скрывать ошибки, которые появились бы при работе с настоящей базой данных.
Скидочная политика также является отдельным компонентом:
const CouponDiscountPolicy = component(
 {
 name: "CouponDiscountPolicy",
 lifetime: "singleton",
 },
 () => class {
 calculate({ cart, subtotal }) {
 if (cart.coupon === "HABR10") {
 return subtotal.percent(10);
 }

 return Money.zero(subtotal.currency);
 }
 },
);
Composition root
Все связи собираются в одном месте:
const container = new Container()
 .registerClass(InMemoryCartRepository, {
 token: CART_REPOSITORY,
 })
 .registerClass(InMemoryProductCatalog, {
 token: PRODUCT_CATALOG,
 })
 .registerClass(CouponDiscountPolicy, {
 token: DISCOUNT_POLICY,
 })
 .registerClass(InMemoryEventBus, {
 token: EVENT_BUS,
 })
 .registerValue(ID_GENERATOR, randomUUID)
 .registerValue(CLOCK, () => new Date())
 .registerClass(CartApplicationService);
Создание request scope выглядит так:
const request = container.createScope([
 [REQUEST_CONTEXT, { id: randomUUID() }],
]);

const carts = request.resolve(CartApplicationService);
После этого можно выполнить прикладной сценарий:
const created = await carts.createCart();
const cartId = created.cart.id;

await carts.addProduct(cartId, "coffee", 2);
await carts.addProduct(cartId, "mug", 1);
await carts.applyCoupon(cartId, "HABR10");

console.dir(await carts.checkout(cartId), {
 depth: null,
});
Для двух чашек кофе по 12,90 евро и одной кружки за 15,90 евро получится subtotal 41,70 евро. Купон
HABR10
даст скидку 4,17 евро, итоговая сумма составит 37,53 евро.
Что в итоге
В результате получился небольшой DI-контейнер, который умеет регистрировать классы, значения и фабрики, поддерживает разные lifetime и при этом не требует TypeScript, декораторов или
reflect-metadata
.
Сам подход довольно простой. Вместо того чтобы пытаться угадать зависимости класса по его конструктору, мы указываем их в момент создания компонента. Класс при этом остается обычным классом: его можно создать через
new
, проверить через
instanceof
, увидеть нормальное имя в stack trace и протестировать отдельно от контейнера.
Конечно, это эксперимент, а не библиотека, которую стоит сразу тащить в продакшен. Здесь нет асинхронной инициализации, автоматического освобождения ресурсов, модулей, optional dependencies и еще десятка вещей, которые постепенно появляются в любом взрослом DI-контейнере. Но основная идея уже работает, а дальше все зависит от того, насколько далеко захочется ее развивать.
Мне в первую очередь было интересно проверить, можно ли сделать удобный DI на чистом JavaScript, не пытаясь превратить его в TypeScript без типов. Похоже, что можно. JavaScript позволяет динамически создавать классы, использовать их как токены и хранить описание зависимостей прямо на них. Этого уже достаточно, чтобы собрать вполне рабочий граф объектов.
При этом я бы не стал оборачивать в
component()
вообще каждый класс приложения.
Cart
,
Money
и другие объекты доменной модели отлично живут без контейнера. DI полезнее оставить на внешнем уровне, где приложение связывается с репозиториями, базами данных, очередями, HTTP-клиентами и другими инфраструктурными деталями.
Полный код примера лежит в репозитории:
https://github.com/kubarskii/simple-di
Спасибо за внимание :)

Эта статья является прямым продолжением 2 части статьи про мой проект
ServeHub-2
. Здесь пойдет речь полностью про разработку установщика на Go Wails v2.
Повествование будет идти таким образом: описание архитектуры в целом, потом код по страницам с картинками как это все выглядит. В отличие от черновика, в этом материале отображен весь рабочий код без сокращений с разбором каждой из страниц.
В Wails основными файлами, с которыми проходит 90% работы это
index.html
,
styles.css
,
main.js
,
app.go
. Остальные файлы мы либо не трогаем, либо настраиваем один раз в самом начале.
Для фронтенда я использовал стандартный html, css, js без современных фреймворков (так как я в них не разбираюсь). Frontend часть подробно рассматривать в этой статье не планируется, a html будет использоваться только чтобы показать, где используются js функции.
Что вообще делает установщик?
Пользователя встречает главная страница с описанием.
Проверка запущен/установлен ли Docker (в нем запускается ansible).
Копирование кода репозитория рядом с установщиком.
Настройка secrets.yml для ansible (форма ввода, данные из которой потом записываются в виде .yml конфига).
Проверка конфигурации: показывается как будет выглядеть сохраненный конфиг, также дается возможность сделать себе копию.
Выбор деплоя (как себя будет вести Ansible). Делится на 3 варианта: для локального сервера, для удаленного сервера и на оба сервера сразу. И каждый из этих вариантов делится еще на 2: полный деплой (с первоначальной настройкой сервера), либо только разворачивание приложений если проект уже запускался.
Подтверждение выбора и начало деплоя. Появляется окно с терминалом в котором пишутся логи ansible.
Если деплой завершился ошибкой - кнопка выйти или запустить заново. Если деплой успешен - небольшой гайд что делать дальше и кнопка выхода.
Экскурс в Wails (как работает)
Wails делится на Frontend и Backend часть. Основной его смысл в том, что он отрисовывает страницы как стандартный браузер и переводит выводы Go функций в js. Получается таким образом: в Go мы пишем основную логику, Wails переводит данные из Go к JS, который уже работает со статикой страниц.
Первоначальная настройка
Про установку много рассказывать не буду, для работы понадобятся:
Go 1.21+
NPM / Node.js (15+)
Wails v2
libwebkit2gtk-4.1-dev
—
только для Linux
(необходим для работы графического движка Wails)
Чтобы создать первоначальную структуру файлов в терминале нужно выполнить
wails init
.
Первый файл с которым предстоит работать -
main.go
(здесь мы создаем наше приложение, даем ему базовые настройки по типу размера окна, привязываем ассеты).
main.go:
package main // Объявление основного пакета приложения

import (
	"embed" // Библиотека для внедрения статических файлов в бинарный код приложения

	"github.com/wailsapp/wails/v2" // Основной пакет фреймворка Wails
	"github.com/wailsapp/wails/v2/pkg/options" // Конфигурационные параметры приложения
	"github.com/wailsapp/wails/v2/pkg/options/assetserver" // Настройки сервера статических файлов
)

// Директива компилятора go:embed:
// Указывает компилятору включить содержимое папки 'frontend/dist' в скомпилированный файл.
// 'all:' гарантирует, что будут включены скрытые файлы (начинающиеся с точки) 
// и файлы с нижним подчеркиванием.
//
//go:embed all:frontend/dist
var assets embed.FS // Переменная 'assets' представляет собой виртуальную файловую систему, содержащую все упакованные ресурсы

func main() {
	// Создаем экземпляр структуры App (содержит логику методов Go, доступных из JS)
	app := NewApp()

	// Запуск приложения Wails с заданными параметрами конфигурации:
	err := wails.Run(&options.App{
 Title: "ServeHub-2 Installer", // Заголовок окна приложения
 Width: 1024, // Ширина окна
 Height: 768, // Высота окна
 Frameless: true, // Отключение системной рамки для создания кастомного интерфейса
 AssetServer: &assetserver.Options{
 Assets: assets, // Привязываем внедренную файловую систему к серверу ассетов
 },
 OnStartup: app.startup, // Метод, вызываемый при запуске приложения для инициализации контекста
 Bind: []interface{}{ // Регистрация экземпляра App для вызова его методов из JavaScript
 app,
 },
	})

	// Если при запуске произошла критическая ошибка, выводим её в консоль
	if err != nil {
 println("Error:", err.Error())
	}
}
Логика смены страниц
Изначально Wails - это SPA, т.е все происходит на одной странице, а javascript меняет ее наполнение, поэтому чтобы реализовать приложение с несколькими страницами я использовал механизм “шагов”.
index.html (Контейнер прогресс-бара):
<!-- Контейнер для отображения прогресса установки -->
<div class="progress-container">
 <!-- 
 Область визуализации шагов. 
 Здесь должны находиться элементы с классом .step-dot, 
 которые JavaScript будет обновлять через функцию updateStepProgress.
 -->
 <div class="progress-bar-track">
 <div id="step-progress-fill" class="progress-bar-fill"></div>

 <!-- Пример точек прогресса, соответствующих 7 шагам -->
 <div class="step-dot" data-step="1"></div>
 <div class="step-dot" data-step="2"></div>
 <div class="step-dot" data-step="3"></div>
 <div class="step-dot" data-step="4"></div>
 <div class="step-dot" data-step="5"></div>
 <div class="step-dot" data-step="6"></div>
 <div class="step-dot" data-step="7"></div>
 </div>

 <!-- Текстовое описание текущего этапа -->
 <div class="step-label">
 Шаг <span id="step-progress-current">1</span> из 7 — 
 <span id="step-progress-title">Добро пожаловать</span>
 </div>
</div>
Для управления навигацией написаны соответствующие функции, которые связывают элементы HTML и логику
App.js
.
main.js (Глобальные функции и роутер):
/**
 * Словарь названий шагов для отображения в прогресс-баре.
 */
const STEP_TITLES = {
 1: 'Добро пожаловать',
 2: 'Проверка требований',
 3: 'Установка компонентов',
 4: 'Настройка secrets.yml',
 5: 'Проверка конфигурации',
 6: 'Выбор сценария деплоя',
 7: 'Запуск деплоя',
};

/**
 * Обновляет визуальное состояние прогресс-бара и индикаторов шагов.
 * @param {number} stepNumber - Текущий номер шага.
 */
function updateStepProgress(stepNumber) {
 const totalSteps = 7;
 const fill = document.getElementById('step-progress-fill');
 const currentEl = document.getElementById('step-progress-current');
 const titleEl = document.getElementById('step-progress-title');

 // 1. Обновление ширины прогресс-бара (процент заполнения)
 if (fill) {
 // Вычисляем процент так, чтобы на 1-м шаге было 0%, а на последнем — 100%
 const pct = ((stepNumber - 1) / (totalSteps - 1)) * 100;
 fill.style.width = `${pct}%`;
 }

 // 2. Обновление текстовых индикаторов
 if (currentEl) currentEl.innerText = stepNumber;
 if (titleEl) titleEl.innerText = STEP_TITLES[stepNumber] || '';

 // 3. Обновление визуальных точек (dots) прогресса
 document.querySelectorAll('.step-dot').forEach((dot) => {
 const dotStep = parseInt(dot.getAttribute('data-step'), 10);
 dot.classList.remove('completed', 'active');

 // Подсвечиваем пройденные шаги как 'completed', текущий — как 'active'
 if (dotStep < stepNumber) dot.classList.add('completed');
 if (dotStep === stepNumber) dot.classList.add('active');
 });
}

/**
 * Главный переключатель экранов мастера установки.
 * Скрывает неактивные шаги и отображает целевой.
 * @param {number} stepNumber - Номер шага для перехода.
 */
window.goToStep = function(stepNumber) {
 // 1. Скрытие всех экранов шагов
 document.querySelectorAll('.step').forEach(step => {
 step.classList.remove('active');
 });

 // 2. Отображение целевого экрана
 const nextStep = document.getElementById(`step-${stepNumber}`);
 if (nextStep) {
 nextStep.classList.add('active');
 }

 // 3. Обновление прогресс-бара
 updateStepProgress(stepNumber);

 // 4. Триггеры автоматической логики:
 // При переходе на определенные шаги запускаем соответствующие скрипты (проверки или установку).
 if (stepNumber === 2) {
 runDockerCheck();
 }
 if (stepNumber === 3) {
 runInstallation();
 }
}
Ревью по страницам
Шаг 1: Добро пожаловать (SPA и Роутинг)
На первом экране отображается базовая информация и кнопка запуска. По нажатию вызывается глобальная функция
goToStep(2)
, инициирующая проверку окружения.
HTML-разметка шага (
index.html
):
<!-- 
 Главный контейнер мастера установки ServeHub-2.
 Используется как точка входа для пользователя при первом запуске приложения.
-->
<div class="installer-container">
 <header class="installer-header">
 <h1>ServeHub-2</h1>
 <p class="subtitle">Мастер установки</p>
 </header>

 <main class="installer-content">
 <p>Добро пожаловать! Эта программа поможет вам установить и настроить проект <strong>ServeHub-2</strong> на вашем компьютере.</p>
 </main>

